def configure_kong(client: KongAdminClient, config: Dict[str, Any]) -> Dict[str, Any]:
    results: Dict[str, Any] = {
        "upstreams": [],
        "targets": [],
        "services": [],
        "routes": [],
    }

    for upstream in config.get("upstreams", []):
        upstream_name = upstream["name"]
        created_upstream = client.create_upstream(
            name=upstream_name,
            algorithm=upstream.get("algorithm", "round-robin"),
            slots=upstream.get("slots", 10000),
        )
        results["upstreams"].append(created_upstream)

        for target in upstream.get("targets", []):
            created_target = client.create_target(
                upstream_name=upstream_name,
                target=target["target"],
                weight=target.get("weight", 100),
            )
            results["targets"].append(created_target)

    for service in config.get("services", []):
        created_service = client.create_service(
            name=service["name"],
            host=service["host"],
            port=service.get("port", 80),
            protocol=service.get("protocol", "http"),
            path=service.get("path"),
            retries=service.get("retries", 5),
            connect_timeout=service.get("connect_timeout", 60000),
            write_timeout=service.get("write_timeout", 60000),
            read_timeout=service.get("read_timeout", 60000),
        )
        results["services"].append(created_service)

        for route in service.get("routes", []):
            created_route = client.create_route(
                service_name=service["name"],
                route_name=route["name"],
                paths=route.get("paths"),
                methods=route.get("methods"),
                hosts=route.get("hosts"),
                protocols=route.get("protocols", ["http", "https"]),
                strip_path=route.get("strip_path", True),
                preserve_host=route.get("preserve_host", False),
            )
            results["routes"].append(created_route)

    return results


def load_config_from_file(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


