def main() -> int:
    config_path = os.getenv("KONG_CONFIG_FILE")
    config = load_config_from_file(config_path) if config_path else default_config()

    client = KongAdminClient(
        admin_url=KONG_ADMIN_URL,
        timeout=REQUEST_TIMEOUT,
        retries=RETRY_COUNT,
        retry_delay=RETRY_DELAY,
    )

    try:
        results = configure_kong(client, config)
        print(json.dumps(results, indent=2))
        return 0
    except Exception as exc:
        print(f"Error configuring Kong: {exc}", file=sys.stderr)
